import React from "react";
import { BrowserRouter as Router, Routes, Route, Navigate, useLocation } from "react-router-dom";
import NavBar from "./components/navBar.js";
import InicioPage from "./pages/InicioPage.js";
import ListarTodosCorridasPage from "./pages/ListarTodosCorridasPage.js";
import RotaCorridaPage from "./pages/RotaCorridaPage.js";
import CadastrarMotoristaPage from "./pages/CadastrarMotoristaPage.js";
import CadastrarIdosoPage from "./pages/CadastrarIdosoPage.js";
import RelacionarMotoristaIdosoPage from "./pages/RelacionarMotoristaIdosoPage.js";
import ListarTodosDadosPage from "./pages/ListarTodosDadosPage.js";
import HistoricoPage from "./pages/HistoricoPage.js";
import { CorridaEmAndamentoProvider, useCorridaEmAndamento } from "./contexts/CorridaEmAndamentoContext.jsx";
import MapaRotaComponent from "./components/MapaRotaComponent.jsx";

function ModalCorridaEmAndamento() {
    const { corridaModal, closeCorridaModal } = useCorridaEmAndamento();
    if (!corridaModal) return null;

    const handleFinalizar = () => {
        if (corridaModal.onFinalizar) corridaModal.onFinalizar();
        closeCorridaModal();
    };

    return (
        <div
            className="modal fade show d-block"
            style={{ backgroundColor: "rgba(0,0,0,0.6)" }}
            role="dialog"
            aria-modal="true"
            aria-labelledby="modalCorridaLabel"
        >
            <div className="modal-dialog modal-xl modal-dialog-centered modal-fullscreen-lg-down" style={{ maxWidth: "95vw" }}>
                <div className="modal-content h-100" style={{ minHeight: "85vh" }}>
                    <div className="modal-header py-2">
                        <h5 className="modal-title" id="modalCorridaLabel">Corrida em andamento</h5>
                        <button
                            type="button"
                            className="btn-close"
                            aria-label="Fechar (corrida continua em andamento)"
                            title="Fechar. A corrida continua em andamento; você pode reabri-la pela lista."
                            onClick={closeCorridaModal}
                        />
                    </div>
                    <div className="modal-body p-0 d-flex flex-column" style={{ minHeight: "70vh" }}>
                        <MapaRotaComponent
                            initialEnderecoOrigem={corridaModal.enderecoOrigem}
                            initialEnderecoDestino={corridaModal.enderecoDestino}
                            corridaId={corridaModal.corridaId}
                            embedInModal={true}
                            onFinalizar={handleFinalizar}
                        />
                    </div>
                </div>
            </div>
        </div>
    );
}

function AppContent() {
  const location = useLocation();
  const isInicio = location.pathname === "/inicio" || location.pathname === "/";
  return (
      <div className="container app-container" style={{marginTop: "80px", marginBottom: "20px"}}>
          {!isInicio && <h1 style={{textAlign: "center"}}>Bem-vindo</h1>}
          <div className="content">
              <Routes>
                  <Route path="/" element={<Navigate to="/inicio" replace />} />
                  <Route path="/inicio" element={<InicioPage/>}/>
                  <Route path="/cadastrarMotorista" element={<CadastrarMotoristaPage/>}/>
                  <Route path="/cadastrarIdoso" element={<CadastrarIdosoPage/>}/>
                  <Route path="/relacionarMotoristaIdoso" element={<RelacionarMotoristaIdosoPage/>}/>
                  <Route path="/listarTodosCorridas" element={<ListarTodosCorridasPage/>}/>
                  <Route path="/rotaCorrida" element={<RotaCorridaPage/>}/>
                  <Route path="/listarTodosDados" element={<ListarTodosDadosPage/>}/>
                  <Route path="/historico" element={<HistoricoPage/>}/>
              </Routes>
          </div>
          <ModalCorridaEmAndamento />
      </div>
  );
}

function App() {
  return (
      <Router>
          <CorridaEmAndamentoProvider>
              <NavBar/>
              <AppContent />
          </CorridaEmAndamentoProvider>
      </Router>
  );
}

export default App;
